import React, { useState, useEffect } from 'react';
import { useAuth } from '../App';
import api from '../api';

const ADMIN_TABS = [
  { key: 'overview', label: '📊 Overview' },
  { key: 'users', label: '👥 Users' },
  { key: 'deficiencies', label: '🥬 Deficiencies' },
];

// ── Overview ──────────────────────────────────────────────────────────────────
function Overview() {
  const [stats, setStats] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    api.get('/api/admin/stats').then(r => { setStats(r.data); setLoading(false); }).catch(() => setLoading(false));
  }, []);

  if (loading) return <div style={{ textAlign: 'center', padding: '2rem' }}><span className="spinner" style={{ margin: '0 auto', display: 'block' }} /></div>;
  if (!stats) return <div className="alert alert-error">Failed to load stats.</div>;

  const CARDS = [
    { label: 'Total Users', value: stats.users, color: '#16a34a', icon: '👥' },
    { label: 'AI Analyses', value: stats.analyses, color: '#0891b2', icon: '🩺' },
    { label: 'Hospitals', value: stats.hospitals, color: '#d97706', icon: '🏥' },
  ];

  return (
    <div>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(180px, 1fr))', gap: 12, marginBottom: '1.5rem' }}>
        {CARDS.map(c => (
          <div key={c.label} className="card" style={{ textAlign: 'center', border: `1px solid ${c.color}25` }}>
            <div style={{ fontSize: '2rem', marginBottom: 4 }}>{c.icon}</div>
            <div style={{ fontSize: '2rem', fontWeight: 800, fontFamily: 'Fraunces, serif', color: c.color }}>{c.value}</div>
            <div style={{ fontSize: '0.8rem', color: '#6b7280', fontWeight: 600 }}>{c.label}</div>
          </div>
        ))}
      </div>

      <div className="card">
        <h4 style={{ fontFamily: 'Outfit, sans-serif', fontWeight: 700, marginBottom: '1rem', fontSize: '0.95rem' }}>Recent Analyses</h4>
        {stats.recent?.length ? (
          <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
            {stats.recent.map((r, i) => (
              <div key={i} style={{ padding: '8px 12px', background: '#f9fafb', borderRadius: 8, fontSize: '0.82rem' }}>
                <div style={{ color: '#6b7280', marginBottom: 2 }}>{new Date(r.timestamp).toLocaleString('en-KE')}</div>
                <div style={{ color: '#374151' }}>"{r.symptoms.substring(0, 80)}{r.symptoms.length > 80 ? '...' : ''}"</div>
              </div>
            ))}
          </div>
        ) : <p style={{ color: '#6b7280', fontSize: '0.875rem' }}>No analyses yet.</p>}
      </div>

      <div className="card" style={{ marginTop: '1rem' }}>
        <h4 style={{ fontFamily: 'Outfit, sans-serif', fontWeight: 700, marginBottom: '1rem', fontSize: '0.95rem' }}>System Status</h4>
        <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
          {[
            { label: 'Flask API', status: 'Online', color: '#16a34a' },
            { label: 'SQLite Database', status: 'Healthy', color: '#16a34a' },
            { label: 'AI Engine (Rule-based NLP)', status: 'Active', color: '#16a34a' },
            { label: 'OpenStreetMap', status: 'Free / No key needed', color: '#16a34a' },
            { label: 'Email Service', status: 'Not configured (optional)', color: '#d97706' },
          ].map(s => (
            <div key={s.label} style={{ display: 'flex', justifyContent: 'space-between', padding: '8px 0', borderBottom: '1px solid #f1f1f1' }}>
              <span style={{ fontSize: '0.875rem', color: '#374151' }}>{s.label}</span>
              <span style={{ fontSize: '0.78rem', fontWeight: 700, color: s.color }}>● {s.status}</span>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

// ── Users ──────────────────────────────────────────────────────────────────────
function Users() {
  const [users, setUsers] = useState([]);
  const [search, setSearch] = useState('');
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    api.get('/api/admin/users').then(r => { setUsers(r.data); setLoading(false); }).catch(() => setLoading(false));
  }, []);

  const filtered = users.filter(u => !search || u.name?.toLowerCase().includes(search.toLowerCase()) || u.email?.toLowerCase().includes(search.toLowerCase()));

  if (loading) return <div style={{ textAlign: 'center', padding: '2rem' }}><span className="spinner" style={{ margin: '0 auto', display: 'block' }} /></div>;

  return (
    <div>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem' }}>
        <h4 style={{ fontFamily: 'Outfit, sans-serif', fontWeight: 700, fontSize: '0.95rem' }}>{users.length} Registered Users</h4>
        <input className="form-input" value={search} onChange={e => setSearch(e.target.value)} placeholder="Search..." style={{ width: 220 }} />
      </div>
      <div style={{ background: 'white', borderRadius: 12, border: '1px solid #e5e7eb', overflow: 'hidden' }}>
        <table style={{ width: '100%', borderCollapse: 'collapse' }}>
          <thead style={{ background: '#f9fafb' }}>
            <tr>
              {['Name', 'Email', 'Role', 'Analyses', 'Joined'].map(h => (
                <th key={h} style={{ padding: '10px 14px', textAlign: 'left', fontSize: '0.7rem', fontWeight: 700, color: '#6b7280', textTransform: 'uppercase', letterSpacing: '0.05em', borderBottom: '1px solid #e5e7eb' }}>{h}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {filtered.map((u, i) => (
              <tr key={u.id} style={{ background: i % 2 === 0 ? 'white' : '#fafafa' }}>
                <td style={{ padding: '10px 14px', borderBottom: '1px solid #f1f1f1' }}>
                  <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                    <div style={{ width: 28, height: 28, borderRadius: '50%', background: u.role === 'ADMIN' ? 'linear-gradient(135deg, #dc2626, #b91c1c)' : 'linear-gradient(135deg, #16a34a, #15803d)', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'white', fontSize: '0.78rem', fontWeight: 700 }}>
                      {(u.name || 'U')[0].toUpperCase()}
                    </div>
                    <span style={{ fontSize: '0.875rem', fontWeight: 600 }}>{u.name}</span>
                  </div>
                </td>
                <td style={{ padding: '10px 14px', fontSize: '0.8rem', color: '#6b7280', borderBottom: '1px solid #f1f1f1' }}>{u.email}</td>
                <td style={{ padding: '10px 14px', borderBottom: '1px solid #f1f1f1' }}>
                  <span style={{ background: u.role === 'ADMIN' ? '#fef2f2' : '#f0fdf4', color: u.role === 'ADMIN' ? '#dc2626' : '#16a34a', borderRadius: 8, padding: '2px 8px', fontSize: '0.7rem', fontWeight: 700 }}>{u.role}</span>
                </td>
                <td style={{ padding: '10px 14px', fontSize: '0.8rem', color: '#374151', borderBottom: '1px solid #f1f1f1' }}>{u.analyses_count}</td>
                <td style={{ padding: '10px 14px', fontSize: '0.78rem', color: '#6b7280', borderBottom: '1px solid #f1f1f1' }}>{u.created_at ? new Date(u.created_at).toLocaleDateString('en-KE') : '—'}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

// ── Deficiencies Knowledge Base View ─────────────────────────────────────────
const DEFS = [
  { id: 'iron', icon: '🩸', name: 'Iron Deficiency Anaemia', color: '#dc2626', stat: '~35% of Kenyan women', symptoms: 10, foods: 7 },
  { id: 'vitamin_a', icon: '👁️', name: 'Vitamin A Deficiency', color: '#d97706', stat: '~35% of children under 5', symptoms: 10, foods: 7 },
  { id: 'vitamin_d', icon: '☀️', name: 'Vitamin D Deficiency', color: '#f59e0b', stat: 'Common indoors despite equatorial sun', symptoms: 11, foods: 5 },
  { id: 'vitamin_b12', icon: '🧠', name: 'Vitamin B12 Deficiency', color: '#0891b2', stat: 'Rising with vegetarianism', symptoms: 12, foods: 5 },
  { id: 'folate', icon: '🍃', name: 'Folate Deficiency', color: '#16a34a', stat: 'Critical for pregnant women', symptoms: 11, foods: 7 },
  { id: 'iodine', icon: '🦋', name: 'Iodine Deficiency', color: '#7c3aed', stat: 'Rift Valley goitre belt', symptoms: 14, foods: 4 },
  { id: 'zinc', icon: '🛡️', name: 'Zinc Deficiency', color: '#0f766e', stat: 'Contributes to 26% child stunting', symptoms: 10, foods: 6 },
  { id: 'calcium', icon: '🦴', name: 'Calcium Deficiency', color: '#64748b', stat: 'Low dairy communities', symptoms: 11, foods: 6 },
  { id: 'vitamin_c', icon: '🍊', name: 'Vitamin C Deficiency', color: '#ea580c', stat: 'Low fruit/veg households', symptoms: 9, foods: 5 },
  { id: 'protein', icon: '💪', name: 'Protein Deficiency', color: '#b45309', stat: '11% of children under 5', symptoms: 14, foods: 6 },
];

function Deficiencies() {
  return (
    <div>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: 10, marginBottom: '1.25rem' }}>
        {[
          { label: 'Total Deficiencies', value: DEFS.length, color: '#16a34a' },
          { label: 'Total Symptoms Mapped', value: DEFS.reduce((a, d) => a + d.symptoms, 0), color: '#0891b2' },
          { label: 'Food Recommendations', value: DEFS.reduce((a, d) => a + d.foods, 0), color: '#d97706' },
          { label: 'Kenya-Specific Stats', value: DEFS.length, color: '#7c3aed' },
        ].map(s => (
          <div key={s.label} className="card" style={{ textAlign: 'center' }}>
            <div style={{ fontSize: '1.5rem', fontWeight: 800, fontFamily: 'Fraunces, serif', color: s.color }}>{s.value}</div>
            <div style={{ fontSize: '0.7rem', color: '#6b7280', fontWeight: 600 }}>{s.label}</div>
          </div>
        ))}
      </div>
      <div className="card">
        <table style={{ width: '100%', borderCollapse: 'collapse' }}>
          <thead style={{ background: '#f9fafb' }}>
            <tr>
              {['Deficiency', 'Kenya Prevalence', 'Symptoms', 'Foods', 'Status'].map(h => (
                <th key={h} style={{ padding: '10px 14px', textAlign: 'left', fontSize: '0.7rem', fontWeight: 700, color: '#6b7280', textTransform: 'uppercase', letterSpacing: '0.05em', borderBottom: '1px solid #e5e7eb' }}>{h}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {DEFS.map((d, i) => (
              <tr key={d.id} style={{ background: i % 2 === 0 ? 'white' : '#fafafa' }}>
                <td style={{ padding: '12px 14px', borderBottom: '1px solid #f1f1f1' }}>
                  <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                    <span style={{ fontSize: '1.3rem' }}>{d.icon}</span>
                    <span style={{ fontWeight: 700, fontSize: '0.875rem', color: d.color }}>{d.name}</span>
                  </div>
                </td>
                <td style={{ padding: '12px 14px', fontSize: '0.78rem', color: '#6b7280', borderBottom: '1px solid #f1f1f1', maxWidth: 200 }}>{d.stat}</td>
                <td style={{ padding: '12px 14px', fontSize: '0.875rem', fontWeight: 600, color: '#374151', borderBottom: '1px solid #f1f1f1' }}>{d.symptoms}</td>
                <td style={{ padding: '12px 14px', fontSize: '0.875rem', fontWeight: 600, color: '#374151', borderBottom: '1px solid #f1f1f1' }}>{d.foods}</td>
                <td style={{ padding: '12px 14px', borderBottom: '1px solid #f1f1f1' }}>
                  <span style={{ background: '#f0fdf4', color: '#16a34a', borderRadius: 8, padding: '2px 8px', fontSize: '0.7rem', fontWeight: 700 }}>Active</span>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

// ── Admin Shell ───────────────────────────────────────────────────────────────
export default function Admin() {
  const { user, logout } = useAuth();
  const [tab, setTab] = useState('overview');

  return (
    <div style={{ display: 'flex', minHeight: 'calc(100vh - 64px)' }}>
      {/* Sidebar */}
      <div style={{ width: 220, background: '#0f172a', display: 'flex', flexDirection: 'column', padding: '1.5rem 0.75rem', flexShrink: 0 }}>
        <div style={{ padding: '0 0.5rem 1.25rem', borderBottom: '1px solid rgba(255,255,255,0.1)', marginBottom: '1rem' }}>
          <div style={{ fontSize: '0.65rem', fontWeight: 700, color: 'rgba(255,255,255,0.3)', textTransform: 'uppercase', letterSpacing: '0.1em', marginBottom: 8 }}>Admin Console</div>
          <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
            <div style={{ width: 32, height: 32, borderRadius: '50%', background: 'linear-gradient(135deg, #16a34a, #15803d)', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'white', fontWeight: 700, fontSize: '0.85rem' }}>
              {(user?.name || 'A')[0].toUpperCase()}
            </div>
            <div>
              <div style={{ color: 'white', fontSize: '0.82rem', fontWeight: 600 }}>{user?.name}</div>
              <div style={{ color: '#4ade80', fontSize: '0.68rem' }}>Administrator</div>
            </div>
          </div>
        </div>
        <nav style={{ flex: 1 }}>
          {ADMIN_TABS.map(t => (
            <button key={t.key} onClick={() => setTab(t.key)} style={{ display: 'flex', alignItems: 'center', gap: 8, width: '100%', padding: '0.6rem 0.75rem', border: 'none', borderRadius: 8, cursor: 'pointer', background: tab === t.key ? '#16a34a' : 'transparent', color: tab === t.key ? 'white' : 'rgba(255,255,255,0.6)', fontFamily: 'Outfit, sans-serif', fontSize: '0.85rem', fontWeight: tab === t.key ? 600 : 400, marginBottom: 2, textAlign: 'left', transition: 'all 0.15s' }}>
              {t.label}
            </button>
          ))}
        </nav>
      </div>

      {/* Main */}
      <div style={{ flex: 1, padding: '1.5rem', overflow: 'auto', background: '#f9fafb' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.25rem' }}>
          <h2 style={{ fontSize: '1.3rem' }}>{ADMIN_TABS.find(t => t.key === tab)?.label}</h2>
          <div style={{ fontSize: '0.78rem', color: '#6b7280', background: '#f0fdf4', border: '1px solid #bbf7d0', borderRadius: 20, padding: '4px 12px' }}>
            ● All Systems Online
          </div>
        </div>
        {tab === 'overview' && <Overview />}
        {tab === 'users' && <Users />}
        {tab === 'deficiencies' && <Deficiencies />}
      </div>
    </div>
  );
}
